"use client";

import { useRef, useEffect, useState } from "react";
import Link from "next/link";
import StepShell from "@/components/StepShell";
import { getNextStep } from "@/content";
import { triggerShake } from "@/lib/learningMessages";

// ===== 三种格子配置 =====
type GridSize = "large" | "medium" | "small";

const GRID_CONFIG: Record<GridSize, { label: string; count: number; cellPx: number; cellPy: number; color: string }> = {
  large: { label: "大格", count: 6, cellPx: 80, cellPy: 60, color: "var(--signal-confirmed)" },
  medium: { label: "中格", count: 12, cellPx: 60, cellPy: 40, color: "var(--accent)" },
  small: { label: "小格", count: 24, cellPx: 40, cellPy: 30, color: "var(--signal-success)" },
};

// 长方形固定为 240px × 120px
// 大格 80×60 → 3列 × 2行 = 6 个
// 中格 60×40 → 4列 × 3行 = 12 个
// 小格 40×30 → 6列 × 4行 = 24 个

type Phase = "intro" | "covering" | "compare" | "question" | "result";

export default function ComparePage() {
  const [phase, setPhase] = useState<Phase>("intro");
  const [activeGrid, setActiveGrid] = useState<GridSize>("large");
  const [coveredCount, setCoveredCount] = useState<Record<GridSize, number>>({
    large: 0,
    medium: 0,
    small: 0,
  });
  const [isAnimating, setIsAnimating] = useState(false);
  const [selectedAnswer, setSelectedAnswer] = useState<number | null>(null);

  // 存储 interval / timeout ID，组件 unmount 时统一清除
  const timerRefs = useRef<ReturnType<typeof setInterval>[]>([]);

  useEffect(() => {
    return () => {
      timerRefs.current.forEach((id) => {
        clearInterval(id);
        clearTimeout(id);
      });
      timerRefs.current = [];
    };
  }, []);

  // 铺满动画
  const handleCover = (size: GridSize) => {
    if (isAnimating) return;
    if (coveredCount[size] >= GRID_CONFIG[size].count) return;

    setActiveGrid(size);
    setIsAnimating(true);
    setPhase("covering");

    const targetCount = GRID_CONFIG[size].count;
    let current = 0;

    // 用局部变量跟踪最新状态，避免闭包陈旧问题
    let latestCounts = { ...coveredCount };
    const interval = setInterval(() => {
      current++;
      latestCounts = { ...latestCounts, [size]: current };
      setCoveredCount(latestCounts);
      if (current >= targetCount) {
        clearInterval(interval);
        setIsAnimating(false);
        const allDone =
          (size === "large" || latestCounts.large >= GRID_CONFIG.large.count) &&
          (size === "medium" || latestCounts.medium >= GRID_CONFIG.medium.count) &&
          (size === "small" || latestCounts.small >= GRID_CONFIG.small.count);
        const timeout = setTimeout(() => {
          setPhase(allDone ? "compare" : "intro");
        }, 800);
        timerRefs.current.push(timeout);
      }
    }, 300);
    timerRefs.current.push(interval);
  };

  const handleAnswer = (answer: number) => {
    setSelectedAnswer(answer);
    if (answer === 0) {
      setPhase("result");
    } else {
      const qEl = document.getElementById("question-box");
      triggerShake(qEl);
    }
  };

  const nextStep = getNextStep("area", "compare");

  const config = GRID_CONFIG[activeGrid];

  return (
    <StepShell topicId="area" stepId="compare">
      {/* 长方形展示区 */}
      <div className="mb-6 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-sm)]">
        <p className="mb-4 text-center text-sm text-[var(--text-secondary)]">
          看看这个长方形，用不同大小的格子来铺满它
        </p>

        {/* 长方形区域 */}
        <div className="flex justify-center">
          <div
            className="relative rounded-lg overflow-hidden"
            style={{
              width: 240,
              height: 120,
              border: "3px solid var(--text)",
              backgroundColor: "var(--bg-soft)",
            }}
          >
            {/* 格子覆盖层 */}
            {phase !== "result" && (
              <div
                className="absolute inset-0 grid"
                style={{
                  gridTemplateColumns: `repeat(${240 / config.cellPx}, ${config.cellPx}px)`,
                  gridTemplateRows: `repeat(${120 / config.cellPy}, ${config.cellPy}px)`,
                }}
              >
                {Array.from({ length: config.count }).map((_, i) => (
                  <div
                    key={i}
                    className="border border-white/40 transition-all duration-300"
                    style={{
                      backgroundColor: i < coveredCount[activeGrid] ? config.color : "transparent",
                      opacity: i < coveredCount[activeGrid] ? 0.7 : 0,
                      transform: i < coveredCount[activeGrid] ? "scale(1)" : "scale(0.5)",
                    }}
                  />
                ))}
              </div>
            )}

            {/* 结果阶段高亮 */}
            {phase === "result" && (
              <div className="absolute inset-0 flex items-center justify-center">
                <div className="flex gap-4">
                  {(["large", "medium", "small"] as GridSize[]).map((size) => (
                    <div
                      key={size}
                      className="flex flex-col items-center gap-1 rounded-lg p-2 animate-pulse-highlight"
                    >
                      <div
                        className="rounded"
                        style={{
                          width: GRID_CONFIG[size].cellPx * 0.6,
                          height: GRID_CONFIG[size].cellPx * 0.45,
                          backgroundColor: GRID_CONFIG[size].color,
                          opacity: 0.7,
                        }}
                      />
                      <span className="text-xs font-bold text-[var(--text)]">
                        {GRID_CONFIG[size].label}
                      </span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </div>

        {/* 当前格子信息 */}
        <div className="mt-4 text-center">
          <span className="text-sm text-[var(--text-secondary)]">
            当前：{config.label} — 已铺 {coveredCount[activeGrid]} / {config.count} 个
          </span>
        </div>
      </div>

      {/* 格子切换 + 铺满按钮 */}
      {(phase === "intro" || phase === "covering") && (
        <div className="mb-6 rounded-[var(--radius)] border border-[var(--border)] bg-[var(--bg-card)] p-4 shadow-[var(--shadow-sm)]">
          <div className="flex gap-3 justify-center">
            {(["large", "medium", "small"] as GridSize[]).map((size) => {
              const done = coveredCount[size] >= GRID_CONFIG[size].count;
              return (
                <button
                  key={size}
                  onClick={() => setActiveGrid(size)}
                  disabled={isAnimating}
                  className={`rounded-lg px-4 py-3 text-sm font-medium transition-all disabled:opacity-50 ${
                    activeGrid === size
                      ? "ring-2 ring-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                      : "border border-[var(--border)]"
                  }`}
                >
                  {GRID_CONFIG[size].label}
                  {done && <span className="ml-1 text-[var(--signal-success)]">✓</span>}
                </button>
              );
            })}
          </div>

          <div className="mt-4 flex justify-center">
            <button
              onClick={() => handleCover(activeGrid)}
              disabled={isAnimating || coveredCount[activeGrid] >= GRID_CONFIG[activeGrid].count}
              className="rounded-full px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105 disabled:opacity-30 disabled:cursor-not-allowed"
              style={{ backgroundColor: "var(--accent)" }}
            >
              {coveredCount[activeGrid] >= GRID_CONFIG[activeGrid].count
                ? `${GRID_CONFIG[activeGrid].label}已铺满 ✓`
                : `用${GRID_CONFIG[activeGrid].label}铺满 →`}
            </button>
          </div>
        </div>
      )}

      {/* 对比结果 */}
      {phase === "compare" && (
        <div className="mb-6 rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)] animate-float-in">
          <h3 className="mb-4 text-center text-lg font-bold text-[var(--text)]">
            三种格子都铺完了！来看看结果
          </h3>
          <div className="grid grid-cols-3 gap-4">
            {(["large", "medium", "small"] as GridSize[]).map((size) => (
              <div
                key={size}
                className="rounded-lg border border-[var(--border)] bg-[var(--bg-soft)] p-4 text-center"
              >
                <div
                  className="mx-auto mb-2 rounded"
                  style={{
                    width: GRID_CONFIG[size].cellPx * 0.5,
                    height: GRID_CONFIG[size].cellPx * 0.375,
                    backgroundColor: GRID_CONFIG[size].color,
                    opacity: 0.7,
                  }}
                />
                <p className="text-sm text-[var(--text-secondary)]">{GRID_CONFIG[size].label}</p>
                <p className="text-2xl font-bold text-[var(--text)]">
                  {GRID_CONFIG[size].count}
                  <span className="text-sm font-normal text-[var(--text-muted)]"> 个</span>
                </p>
              </div>
            ))}
          </div>

          <div className="mt-6 flex justify-center">
            <button
              onClick={() => setPhase("question")}
              className="rounded-full px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              style={{ backgroundColor: "var(--accent)" }}
            >
              为什么数不一样？→
            </button>
          </div>
        </div>
      )}

      {/* 问题阶段 */}
      {phase === "question" && (
        <div
          id="question-box"
          className="mb-6 rounded-[var(--radius)] border-2 border-[var(--signal-focus)] bg-[var(--bg-card)] p-6 shadow-[var(--shadow-md)]"
        >
          <p className="mb-4 text-center text-[var(--text)] font-medium">
            同一个长方形，为什么数出来的数字不一样？
          </p>
          <div className="grid grid-cols-1 gap-3">
            {[
              { label: "A. 因为格子大小不同", value: 0 },
              { label: "B. 因为长方形变了", value: 1 },
              { label: "C. 因为数错了", value: 2 },
            ].map((opt) => (
              <button
                key={opt.value}
                onClick={() => handleAnswer(opt.value)}
                className={`rounded-lg border px-4 py-3 text-sm font-medium transition-all hover:border-[var(--primary-light)] hover:bg-[var(--signal-focus)]/10 ${
                  selectedAnswer === opt.value
                    ? "border-[var(--signal-focus)] bg-[var(--signal-focus)]/10"
                    : "border-[var(--border)] bg-[var(--bg-soft)]"
                }`}
              >
                {opt.label}
              </button>
            ))}
          </div>
          {selectedAnswer !== null && selectedAnswer !== 0 && (
            <p className="mt-4 text-center text-sm text-[var(--text-secondary)]">
              💡 再看看上面的对比图，长方形变了吗？
            </p>
          )}
        </div>
      )}

      {/* 结果阶段 */}
      {phase === "result" && (
        <div className="space-y-4">
          <div className="rounded-[var(--radius)] border-2 border-[var(--signal-success)] bg-[var(--bg-card)] p-6 text-center shadow-[var(--shadow-md)] animate-float-in">
            <div className="text-3xl mb-2">🎉</div>
            <p className="text-lg font-semibold text-[var(--text)]">
              格子越多，数出来的数越大！
            </p>
            <p className="mt-2 text-sm text-[var(--text-secondary)]">
              如果大家用一样大小的格子，数出来的数就一样了——这就是&quot;统一单位&quot;
            </p>

            {/* 高亮格子大小差异 */}
            <div className="mt-6 flex justify-center gap-6">
              {(["large", "medium", "small"] as GridSize[]).map((size) => (
                <div key={size} className="flex flex-col items-center gap-1">
                  <div
                    className="rounded animate-pulse-highlight"
                    style={{
                      width: GRID_CONFIG[size].cellPx * 0.6,
                      height: GRID_CONFIG[size].cellPx * 0.45,
                      backgroundColor: GRID_CONFIG[size].color,
                      opacity: 0.7,
                    }}
                  />
                  <span className="text-xs text-[var(--text-muted)]">
                    {GRID_CONFIG[size].count} 个
                  </span>
                </div>
              ))}
            </div>
          </div>

          <div className="flex justify-center gap-4">
            <button
              onClick={() => {
                setPhase("intro");
                setCoveredCount({ large: 0, medium: 0, small: 0 });
                setSelectedAnswer(null);
                setActiveGrid("large");
              }}
              className="rounded-full border border-[var(--border)] px-6 py-3 font-medium text-[var(--text-secondary)] transition-all hover:bg-[var(--bg-soft)]"
            >
              再玩一次
            </button>
            {nextStep && (
              <Link
                href={nextStep.path}
                className="rounded-full bg-[var(--accent)] px-6 py-3 font-semibold text-white shadow-[var(--shadow-accent)] transition-all hover:scale-105"
              >
                下一步：{nextStep.label} →
              </Link>
            )}
          </div>
        </div>
      )}
    </StepShell>
  );
}
